mapper.select:
/* com.educare.edu.comn.mapper.MovMapper.getMovList */
	SELECT a.* FROM (
		SELECT a.*,@rnum:=@rnum+1 AS R_NUM
 		FROM t_lecture_mov a ,(SELECT @rnum:=0) b 
 		WHERE 1=1

			AND ORG_CD=#{orgCd}


			AND reg_id=#{regId}


 			AND (
				TITLE LIKE CONCAT('%',#{srchWrd},'%')
				OR CONTENT LIKE CONCAT('%',#{srchWrd},'%')
				OR FILE_ORG LIKE CONCAT('%',#{srchWrd},'%')
			)

		ORDER BY REG_TIME DESC
	) a

	LIMIT #{firstRecordIndex},#{recordCountPerPage}

	/* com.educare.edu.comn.mapper.MovMapper.getMovTotalCnt */
		select count(*) from t_lecture_mov where 1=1

			AND ORG_CD=#{orgCd}


			AND reg_id=#{regId}


 			AND (
				TITLE LIKE CONCAT('%',#{srchWrd},'%')
				OR CONTENT LIKE CONCAT('%',#{srchWrd},'%')
				OR FILE_ORG LIKE CONCAT('%',#{srchWrd},'%')
			)
